interface.signature:
interface SnippetResult extends MinimalResult {
  snippet: string;              // 3-5 lines from Vertex AI highlights
  snippet_file_path: string;     // Extracted from highlights metadata
  snippet_line_range: string;    // "45-50" format
  context_lines_before: number;  // Fixed at 2
  context_lines_after: number;   // Fixed at 2
  codespaces_link: string;       // https://github.dev/{org}/{repo}
}

interface SearchResult {
  title: string;
  url: string;
  snippet: string;  // Populated from Vertex AI Search highlights
  metadata: {
    org: string;
    repo: string;
    pushedAt?: string;
    processedAt?: string;
  };
}

const effectiveMode = resultMode || 'snippets';

if (effectiveMode === 'minimal') {
  results = formatMinimal(rawResults);
} else if (effectiveMode === 'snippets') {
  results = formatSnippet(rawResults);
} else {
  // full mode (Story 8.4)
}
